code = """import json

# Load the previous results
prev_result_file = locals()['var_functions.execute_python:44']
cpc_defs_file = locals()['var_functions.query_db:48']

# Read the results
with open(prev_result_file, 'r') as f:
    prev_result = json.load(f)

with open(cpc_defs_file, 'r') as f:
    cpc_defs = json.load(f)

# Create CPC title mapping
cpc_title_map = {}
for item in cpc_defs:
    cpc_title_map[item['symbol']] = item['titleFull']

# Group CPC codes by assignee
assignee_cpc = {}
for result in prev_result['sample_results']:
    assignee = result['assignee']
    if assignee not in assignee_cpc:
        assignee_cpc[assignee] = set()
    assignee_cpc[assignee].update(result['cpc_codes'])

# Build final answer structure
final_results = []
for assignee, cpc_codes in assignee_cpc.items():
    if assignee == 'UNIV CALIFORNIA':
        continue
    
    cpc_list = []
    for code in sorted(cpc_codes):
        if code in cpc_title_map:
            cpc_list.append({
                'cpc_code': code,
                'title': cpc_title_map[code]
            })
    
    final_results.append({
        'assignee': assignee,
        'cpc_subclasses': cpc_list
    })

# Create summary
print('Total assignees excluding UC:', len(final_results))
for item in final_results:
    assignee_name = item['assignee']
    cpc_count = len(item['cpc_subclasses'])
    print('Assignee: ' + assignee_name)
    print('  CPC codes: ' + str(cpc_count))

result_json = json.dumps(final_results, indent=2)
print('__RESULT__:')
print(result_json)"""

